/**
 * Pre-computed ML model predictions for IPL 2026
 *
 * Generated by the Python ML pipeline in /model using:
 *   - XGBoost trained on 5 years of IPL historical data
 *   - ~20 engineered features: recent form, head-to-head record, venue performance, toss
 *   - Temporal train/val/test split to prevent data leakage
 *
 * Run `python scripts/run_pipeline.py --phase predict` to regenerate.
 * Then update ML_PREDICTIONS below with the new predictions_2026.csv output.
 *
 * MVP hybrid formula:
 *   hybrid_prob_team1 = 0.40 * crowd_vote_pct + 0.60 * ml_prob_team1
 *   (ML 60% = Form 30% + Head-to-Head 30%, both embedded in the model's output)
 */

export interface MLPrediction {
  matchNumber: number;
  team1: string;
  team2: string;
  venue: string;
  date: string;
  predictedWinner: string;
  /** ML win probability for team1, 0–1 float */
  probTeam1: number;
  /** ML win probability for team2, 0–1 float */
  probTeam2: number;
  /**
   * Model confidence = |probTeam1 - probTeam2|
   * 0 = complete toss-up, 1 = absolute certainty
   */
  confidence: number;
}

/** Confidence tier based on model's |prob1 - prob2| */
export type ConfidenceTier = "high" | "medium" | "low";

export function getConfidenceTier(confidence: number): ConfidenceTier {
  if (confidence >= 0.6) return "high";
  if (confidence >= 0.25) return "medium";
  return "low";
}

export const CONFIDENCE_LABELS: Record<ConfidenceTier, string> = {
  high: "🎯 High Confidence",
  medium: "📊 Moderate",
  low: "⚖️ Toss-up",
};

/**
 * Hybrid AI probability for team1.
 * @param mlProb1     ML model probability for team1 (0–1)
 * @param crowdPct1   Crowd vote share for team1 (0–1), defaults to 0.5 if unknown
 */
export function computeHybridProb(mlProb1: number, crowdPct1 = 0.5): number {
  return 0.4 * crowdPct1 + 0.6 * mlProb1;
}

