/** Look up by match_number (matches the DB column). */
export function getMLPrediction(matchNumber: number): MLPrediction | null {
  return ML_PREDICTIONS.find((p) => p.matchNumber === matchNumber) ?? null;
}

/**
 * Look up by team pair — order-insensitive.
 * Returns the first entry where {team1, team2} matches in either order.
 */
export function getMLPredictionByTeams(
  team1: string,
  team2: string
): MLPrediction | null {
  return (
    ML_PREDICTIONS.find(
      (p) =>
        (p.team1 === team1 && p.team2 === team2) ||
        (p.team1 === team2 && p.team2 === team1)
    ) ?? null
  );
}
